private IEnumerable<UserCard> GetUserCards(string userId)
{
    var command = _connection.CreateCommand();
    command.CommandText = @"
        SELECT Cards.Id, Units, OwnerId, Cards.Timestamp, Remaining, UserCards.Timestamp
        FROM Cards
        JOIN UserCards ON Cards.Id = UserCards.CardId
        WHERE UserCards.UserId = @UserId;
    ";
    command.Parameters.AddWithValue("@UserId", userId);

    using var reader = command.ExecuteReader();
    while (reader.Read())
    {
        var card = new Card(
            reader.GetString(0),
            reader.GetDouble(1),
            reader.GetInt64(2),
            reader.GetInt64(3),
            reader.GetInt32(4)
        );
        yield return new UserCard(card, reader.GetInt64(5));
    }
}

This implementation of the `GetUserCards` method is good. It retrieves all the cards associated with a user from the database, and creates a `Card` object and a `UserCard` object for each record in the result set.

One possible optimization you can make is to avoid calling `GetString`, `GetDouble`, `GetInt64`, and `GetInt32` for each column in every row. Instead, you can use the column index to access the values directly, like this:

```
private IEnumerable<UserCard> GetUserCards(string userId)
{
    var command = _connection.CreateCommand();
    command.CommandText = @"
        SELECT Cards.Id, Units, OwnerId, Cards.Timestamp, Remaining, UserCards.Timestamp
        FROM Cards
        JOIN UserCards ON Cards.Id = UserCards.CardId
        WHERE UserCards.UserId = @UserId;
    ";
    command.Parameters.AddWithValue("@UserId", userId);

    using var reader = command.ExecuteReader();
    int idColumnIndex = reader.GetOrdinal("Id");
    int unitsColumnIndex = reader.GetOrdinal("Units");
    int ownerIdColumnIndex = reader.GetOrdinal("OwnerId");
    int timestampColumnIndex = reader.GetOrdinal("Timestamp");
    int remainingColumnIndex = reader.GetOrdinal("Remaining");
    int userCardTimestampColumnIndex = reader.GetOrdinal("UserCards.Timestamp");

    while (reader.Read())
    {
        var card = new Card(
            reader.GetString(idColumnIndex),
            reader.GetDouble(unitsColumnIndex),
            reader.GetInt64(ownerIdColumnIndex),
            reader.GetInt64(timestampColumnIndex),
            reader.GetInt32(remainingColumnIndex)
        );
        yield return new UserCard(card, reader.GetInt64(userCardTimestampColumnIndex));
    }
}
```

This can improve performance by avoiding unnecessary method calls, and can make the code easier to read and maintain by using meaningful variable names.
